    98→		if user == nil || !hasString(r.Users, user.GetName()) {
    99→			return false
   100→		}
   101→	}
   102→	if len(r.UserGroups) > 0 {
   103→		if user == nil {
   104→			return false
   105→		}
   106→		matched := false
   107→		for _, group := range user.GetGroups() {
   108→			if hasString(r.UserGroups, group) {
   109→				matched = true
   110→				break
   111→			}
   112→		}
   113→		if !matched {
   114→			return false
   115→		}
   116→	}
